import React, { useState } from 'react';
import { Link } from 'react-router-dom';

function Story({ darkMode }) {
  const [contentPosition, setContentPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const handleMouseDown = (e) => {
    setIsDragging(true);
    setDragStart({
      x: e.clientX - contentPosition.x,
      y: e.clientY - contentPosition.y
    });
  };

  const handleMouseMove = (e) => {
    if (!isDragging) return;
    setContentPosition({
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const colors = {
    bg: darkMode ? '#0f0f0f' : '#fff',
    text: darkMode ? '#fff' : '#000',
    textLight: darkMode ? '#999' : '#666',
    border: darkMode ? '#333' : '#f0f0f0',
    imageBg: darkMode ? '#1a1a1a' : '#f9f9f9'
  };

  const teamMembers = [
    {
      name: 'LENG',
      role: 'Creative Director',
      image: '/HomePagePics1.png',
      bio: 'Visionary behind RAW\'s aesthetic direction'
    },
    {
      name: 'WIN',
      role: 'Brand Strategist',
      image: '/HomePagePics2.png',
      bio: 'Architect of RAW\'s innovative vision'
    },
    {
      name: 'ZAYN',
      role: 'Founder & CEO',
      image: '/HomePagePics3.png',
      bio: 'Driving RAW\'s mission to redefine luxury'
    }
  ];

  return (
    <div style={{
      backgroundImage: 'url(/StoryBg.png)',
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      color: colors.text,
      fontFamily: 'Helvetica, Arial, sans-serif',
      minHeight: '100vh'
    }}>
      {/* Hero Section */}
      <div style={{
        position: 'relative',
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        overflow: 'hidden',
        padding: '60px 50px'
      }}>

        {/* Content */}
        <div style={{
          position: 'relative',
          zIndex: 1,
          textAlign: 'center',
          maxWidth: '700px'
        }}>
          <h1 style={{
            fontSize: 'clamp(36px, 8vw, 64px)',
            fontWeight: '300',
            letterSpacing: '2px',
            margin: '0 0 30px 0',
            textTransform: 'uppercase'
          }}>
            OUR STORY
          </h1>
          <p style={{
            fontSize: '16px',
            fontWeight: '300',
            lineHeight: '1.8',
            color: colors.textLight,
            letterSpacing: '0.5px'
          }}>
            RAW is more than a fashion brand. We are a movement dedicated to authenticity, quality, and timeless elegance. Crafted with intention, worn with purpose.
          </p>
        </div>
      </div>

      {/* Mission Section */}
      <div style={{
        padding: '80px 50px',
        maxWidth: '1200px',
        margin: '0 auto',
        backgroundColor: 'rgba(15, 15, 15, 0.7)',
        backdropFilter: 'blur(10px)'
      }}>
        <h2 style={{
          fontSize: '28px',
          fontWeight: '300',
          letterSpacing: '1px',
          margin: '0 0 40px 0',
          textTransform: 'uppercase'
        }}>
          OUR MISSION
        </h2>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: '60px'
        }}>
          <div>
            <h3 style={{
              fontSize: '13px',
              fontWeight: '600',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              margin: '0 0 20px 0',
              color: colors.textLight
            }}>
              AUTHENTICITY
            </h3>
            <p style={{
              fontSize: '14px',
              fontWeight: '300',
              lineHeight: '1.8',
              color: colors.textLight,
              margin: '0'
            }}>
              Every piece tells a story. We believe in creating garments that reflect who you truly are, not who you're expected to be.
            </p>
          </div>
          <div>
            <h3 style={{
              fontSize: '13px',
              fontWeight: '600',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              margin: '0 0 20px 0',
              color: colors.textLight
            }}>
              QUALITY
            </h3>
            <p style={{
              fontSize: '14px',
              fontWeight: '300',
              lineHeight: '1.8',
              color: colors.textLight,
              margin: '0'
            }}>
              Uncompromising standards in materials and craftsmanship. Each garment is designed to last, to be cherished, and to become a part of your story.
            </p>
          </div>
          <div>
            <h3 style={{
              fontSize: '13px',
              fontWeight: '600',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              margin: '0 0 20px 0',
              color: colors.textLight
            }}>
              SUSTAINABILITY
            </h3>
            <p style={{
              fontSize: '14px',
              fontWeight: '300',
              lineHeight: '1.8',
              color: colors.textLight,
              margin: '0'
            }}>
              We are committed to ethical practices and sustainable production. Fashion should never come at the cost of our planet.
            </p>
          </div>
        </div>
      </div>

      {/* Team Section */}
      <div style={{
        padding: '80px 50px',
        backgroundColor: 'rgba(15, 15, 15, 0.7)',
        backdropFilter: 'blur(10px)'
      }}>
        <h2 style={{
          fontSize: '28px',
          fontWeight: '300',
          letterSpacing: '1px',
          margin: '0 0 60px 0',
          textTransform: 'uppercase',
          textAlign: 'center'
        }}>
          THE PEOPLE BEHIND RAW
        </h2>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: '40px',
          maxWidth: '1200px',
          margin: '0 auto'
        }}>
          {teamMembers.map((member, idx) => (
            <div key={idx} style={{
              textAlign: 'center'
            }}>
              {/* Image */}
              <div style={{
                aspectRatio: '1',
                overflow: 'hidden',
                marginBottom: '30px',
                backgroundColor: colors.border
              }}>
                <img
                  src={member.image}
                  alt={member.name}
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover'
                  }}
                />
              </div>
              {/* Info */}
              <h3 style={{
                fontSize: '16px',
                fontWeight: '500',
                letterSpacing: '1px',
                margin: '0 0 10px 0',
                textTransform: 'uppercase'
              }}>
                {member.name}
              </h3>
              <p style={{
                fontSize: '12px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                color: colors.textLight,
                margin: '0 0 15px 0',
                textTransform: 'uppercase'
              }}>
                {member.role}
              </p>
              <p style={{
                fontSize: '13px',
                fontWeight: '300',
                lineHeight: '1.6',
                color: colors.textLight,
                margin: '0'
              }}>
                {member.bio}
              </p>
            </div>
          ))}
        </div>
      </div>

      {/* CTA Section */}
      <div style={{
        padding: '80px 50px',
        textAlign: 'center',
        backgroundColor: 'rgba(15, 15, 15, 0.7)',
        backdropFilter: 'blur(10px)'
      }}>
        <h2 style={{
          fontSize: '28px',
          fontWeight: '300',
          letterSpacing: '1px',
          margin: '0 0 30px 0',
          textTransform: 'uppercase'
        }}>
          DISCOVER RAW
        </h2>
        <p style={{
          fontSize: '14px',
          fontWeight: '300',
          color: colors.textLight,
          margin: '0 0 40px 0',
          lineHeight: '1.8',
          maxWidth: '600px',
          marginLeft: 'auto',
          marginRight: 'auto'
        }}>
          Explore our curated collection and find pieces that resonate with your authentic self. Every purchase is an investment in quality and timelessness.
        </p>
        <Link
          to="/"
          style={{
            display: 'inline-block',
            padding: '15px 40px',
            backgroundColor: darkMode ? '#fff' : '#000',
            color: darkMode ? '#000' : '#fff',
            textDecoration: 'none',
            fontSize: '12px',
            fontWeight: '400',
            letterSpacing: '1px',
            textTransform: 'uppercase',
            transition: 'opacity 0.3s'
          }}
          onMouseEnter={(e) => e.target.style.opacity = '0.7'}
          onMouseLeave={(e) => e.target.style.opacity = '1'}
        >
          SHOP NOW
        </Link>
      </div>
    </div>
  );
}

export default Story;
